function main(): void {
const overflows = ["constrain", "reject"];
const fields = ["years", "months", "weeks", "days", "hours", "minutes", "seconds", "milliseconds", "microseconds", "nanoseconds"];

const instance = Temporal.PlainDateTime.from({ year: 2000, month: 5, day: 2, minute: 34, second: 56, millisecond: 987, microsecond: 654, nanosecond: 321 });

overflows.forEach((overflow) => {
  fields.forEach((field) => {
    try { (() => instance.add({ [field]: Infinity }, { overflow }))(); console.log("__OK__"); } catch (e) { console.log(e.constructor.name); };
  });
});

let calls = 0;
const obj = {
  valueOf() {
    calls++;
    return Infinity;
  }
};

overflows.forEach((overflow) => {
  fields.forEach((field) => {
    calls = 0;
    try { (() => instance.add({ [field]: obj }, { overflow }))(); console.log("__OK__"); } catch (e) { console.log(e.constructor.name); };
    console.log(calls);
  });
});
}

