function main(): void {
const overflows = ["constrain", "reject"];
const fields = ["years", "months", "weeks", "days", "hours", "minutes", "seconds", "milliseconds", "microseconds", "nanoseconds"];

const instance = Temporal.PlainYearMonth.from({ year: 2000, month: 5 });

overflows.forEach((overflow) => {
  fields.forEach((field) => {
    try { (() => instance.subtract({ [field]: Infinity }, { overflow }))(); console.log("__OK__"); } catch (e) { console.log(e.constructor.name); };
  });
});

let calls = 0;
const obj = {
  valueOf() {
    calls++;
    return Infinity;
  }
};

overflows.forEach((overflow) => {
  fields.forEach((field) => {
    calls = 0;
    try { (() => instance.subtract({ [field]: obj }, { overflow }))(); console.log("__OK__"); } catch (e) { console.log(e.constructor.name); };
    console.log(calls);
  });
});
}

